module RefModule (  
    input wire [7:0] data,  
    input wire we,  
    input wire re,  
    output reg [7:0] q  
);  
    reg [7:0] unused_memory;  

    always @(posedge we) begin  
        unused_memory <= data;  
    end  

    always @(posedge re) begin  
        q <= unused_memory;  
    end  
endmodule
